const html = "<!doctype html>\n<html lang=\"es\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <meta name=\"description\" content=\"Sistema web para comercio con ventas, proveedores, stock y facturacion.\" />\n    <link rel=\"icon\" type=\"image/svg+xml\" href=\"/favicon.svg\" />\n    <link rel=\"stylesheet\" href=\"/app.css\" />\n    <title>Comercio 360</title>\n  </head>\n  <body>\n    <div id=\"app\"></div>\n    <script src=\"/app.js\"></script>\n  </body>\n</html>\n";
const css = "@import url('https://fonts.googleapis.com/css2?family=Oswald:wght@400;500;700&family=Inter:wght@400;500;600;700&display=swap');\n\n:root {\n  --panel: #ffffff;\n  --panel-soft: #f8fafc;\n  --line: rgba(15, 23, 42, 0.1);\n  --text: #111827;\n  --muted: #6b7280;\n  --accent: #d61010;\n  --accent-dark: #980909;\n  --accent-soft: rgba(214, 16, 16, 0.1);\n  --ok: #16a34a;\n  --shadow: 0 16px 40px rgba(15, 23, 42, 0.08);\n  --bg:\n    radial-gradient(circle at top right, rgba(214, 16, 16, 0.08), transparent 18%),\n    linear-gradient(180deg, #eef1f5 0%, #f6f7f9 100%);\n  font-family: 'Inter', sans-serif;\n  color: var(--text);\n  background: var(--bg);\n  font-synthesis: none;\n  text-rendering: optimizeLegibility;\n  -webkit-font-smoothing: antialiased;\n  -moz-osx-font-smoothing: grayscale;\n}\n\n:root[data-theme='dark'] {\n  --panel: #111827;\n  --panel-soft: #0f172a;\n  --line: rgba(255, 255, 255, 0.08);\n  --text: #f3f4f6;\n  --muted: #9ca3af;\n  --accent: #ff3b30;\n  --accent-dark: #b91c1c;\n  --accent-soft: rgba(255, 59, 48, 0.12);\n  --ok: #22c55e;\n  --shadow: 0 18px 42px rgba(0, 0, 0, 0.35);\n  --bg:\n    radial-gradient(circle at top right, rgba(255, 59, 48, 0.14), transparent 18%),\n    linear-gradient(180deg, #0b1020 0%, #0f172a 100%);\n}\n\n* { box-sizing: border-box; }\nhtml { scroll-behavior: smooth; }\nbody { margin: 0; min-width: 320px; background: var(--bg); }\nbutton, input, select { font: inherit; }\nbutton { cursor: pointer; }\ninput, select { outline: none; }\n#app { min-height: 100vh; }\n\n.app-shell {\n  display: grid;\n  grid-template-columns: 96px 1fr;\n  min-height: 100vh;\n}\n\n.sidebar {\n  background: linear-gradient(180deg, var(--panel) 0%, var(--panel-soft) 100%);\n  border-right: 1px solid var(--line);\n  padding: 14px 10px;\n  display: flex;\n  flex-direction: column;\n  gap: 16px;\n  align-items: center;\n}\n\n.brand-logo {\n  width: 56px;\n  height: auto;\n  border-radius: 6px;\n  box-shadow: 0 8px 18px rgba(214, 16, 16, 0.14);\n}\n\n.sidebar-nav {\n  display: grid;\n  gap: 10px;\n  width: 100%;\n}\n\n.nav-square,\n.metric-card,\n.panel,\n.badge,\n.searchbar,\n.theme-toggle {\n  transition:\n    transform 180ms ease,\n    box-shadow 180ms ease,\n    border-color 180ms ease,\n    background 180ms ease,\n    color 180ms ease;\n}\n\n.nav-square {\n  width: 100%;\n  min-height: 74px;\n  border-radius: 16px;\n  border: 1px solid transparent;\n  background: var(--panel);\n  color: var(--accent);\n  display: grid;\n  justify-items: center;\n  align-content: center;\n  gap: 6px;\n  padding: 8px 4px;\n  box-shadow: 0 10px 18px rgba(15, 23, 42, 0.05);\n}\n\n.nav-square:hover {\n  transform: translateY(-2px);\n  border-color: rgba(214, 16, 16, 0.22);\n  box-shadow: 0 18px 28px rgba(214, 16, 16, 0.14);\n}\n\n.nav-icon svg {\n  width: 20px;\n  height: 20px;\n}\n\n.nav-label {\n  font-size: 0.68rem;\n  line-height: 1.1;\n  color: var(--text);\n}\n\n.workspace {\n  display: grid;\n  grid-template-rows: auto 1fr;\n}\n\n.topbar {\n  display: grid;\n  grid-template-columns: 260px minmax(0, 1fr) 240px;\n  gap: 18px;\n  align-items: center;\n  padding: 18px 22px;\n  border-bottom: 1px solid var(--line);\n  background: color-mix(in srgb, var(--panel) 92%, transparent);\n  backdrop-filter: blur(10px);\n}\n\n.topbar-left h1,\n.panel-head h3,\n.metric-card strong,\n.list-row strong,\n.priority-item strong,\n.top-row strong,\n.alert-card strong {\n  font-family: 'Oswald', sans-serif;\n}\n\n.topbar-left h1 {\n  margin: 2px 0;\n  font-size: 2rem;\n  line-height: 1;\n}\n\n.topbar-left span,\n.panel-head p,\n.kicker,\n.metric-card span,\n.metric-card p,\n.list-row p,\n.priority-item p,\n.top-row p,\n.alert-card p {\n  color: var(--muted);\n}\n\n.topbar-left span { font-size: 0.92rem; }\n\n.kicker {\n  margin: 0;\n  text-transform: uppercase;\n  letter-spacing: 0.16em;\n  font-size: 0.72rem;\n}\n\n.searchbar {\n  display: flex;\n  gap: 10px;\n  align-items: center;\n  border: 1px solid var(--line);\n  background: var(--panel);\n  border-radius: 14px;\n  padding: 12px 14px;\n}\n\n.searchbar:hover {\n  transform: translateY(-1px);\n  box-shadow: 0 14px 28px rgba(15, 23, 42, 0.08);\n}\n\n.searchbar span {\n  color: var(--accent);\n  font-weight: 700;\n  font-size: 0.82rem;\n  text-transform: uppercase;\n}\n\n.searchbar input {\n  width: 100%;\n  border: 0;\n  background: transparent;\n  color: var(--text);\n}\n\n.searchbar input::placeholder { color: var(--muted); }\n\n.topbar-right {\n  display: flex;\n  justify-content: flex-end;\n  gap: 10px;\n}\n\n.theme-toggle,\n.badge {\n  border-radius: 999px;\n  padding: 10px 14px;\n  font-size: 0.82rem;\n}\n\n.theme-toggle {\n  border: 1px solid var(--line);\n  background: var(--panel);\n  color: var(--text);\n}\n\n.theme-toggle:hover,\n.badge:hover { transform: translateY(-1px); }\n\n.badge {\n  border: 1px solid color-mix(in srgb, var(--ok) 30%, transparent);\n  background: color-mix(in srgb, var(--ok) 10%, var(--panel));\n  color: color-mix(in srgb, var(--ok) 70%, var(--text));\n}\n\n.page { padding: 22px; }\n\n.metrics-grid,\n.dashboard-grid,\n.content-grid {\n  display: grid;\n  gap: 14px;\n}\n\n.metrics-grid { grid-template-columns: repeat(4, minmax(0, 1fr)); }\n\n.metric-card,\n.panel {\n  border: 1px solid var(--line);\n  background: linear-gradient(180deg, var(--panel) 0%, var(--panel-soft) 100%);\n  box-shadow: var(--shadow);\n}\n\n.metric-card {\n  border-radius: 18px;\n  padding: 20px;\n}\n\n.metric-card:hover {\n  transform: translateY(-3px);\n  box-shadow: 0 20px 38px rgba(15, 23, 42, 0.1);\n}\n\n.metric-card strong {\n  display: block;\n  margin: 10px 0 8px;\n  font-size: 2rem;\n}\n\n.metric-card p { margin: 0; }\n\n.dashboard-grid {\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  margin-top: 14px;\n}\n\n.content-grid {\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  margin-top: 14px;\n}\n\n.panel {\n  border-radius: 18px;\n  padding: 20px;\n}\n\n.panel:hover {\n  transform: translateY(-2px);\n  box-shadow: 0 22px 44px rgba(15, 23, 42, 0.09);\n}\n\n.panel-head { margin-bottom: 14px; }\n\n.panel-head h3 {\n  margin: 0;\n  font-size: 1.45rem;\n}\n\n.panel-head p { margin: 5px 0 0; }\n\n.form-grid {\n  display: grid;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  gap: 12px;\n}\n\n.form-grid label {\n  display: grid;\n  gap: 7px;\n  font-size: 0.86rem;\n}\n\n.form-grid input,\n.form-grid select {\n  width: 100%;\n  border-radius: 12px;\n  border: 1px solid var(--line);\n  background: var(--panel);\n  color: var(--text);\n  padding: 12px 14px;\n}\n\n.form-grid input:hover,\n.form-grid select:hover,\n.form-grid input:focus,\n.form-grid select:focus {\n  border-color: rgba(214, 16, 16, 0.28);\n  box-shadow: 0 0 0 3px rgba(214, 16, 16, 0.08);\n}\n\n.checkbox-row {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  grid-column: span 2;\n}\n\n.checkbox-row input { width: auto; }\n\n.form-grid button {\n  grid-column: span 2;\n  border: 0;\n  border-radius: 14px;\n  background: linear-gradient(180deg, var(--accent) 0%, var(--accent-dark) 100%);\n  color: #ffffff;\n  padding: 14px 18px;\n  font-weight: 700;\n  transition: transform 180ms ease, box-shadow 180ms ease;\n}\n\n.form-grid button:hover {\n  transform: translateY(-2px);\n  box-shadow: 0 18px 30px rgba(214, 16, 16, 0.24);\n}\n\n.list,\n.priority-list,\n.top-list,\n.alert-list {\n  display: grid;\n  gap: 10px;\n}\n\n.list-row,\n.priority-item,\n.top-row,\n.alert-card {\n  display: flex;\n  justify-content: space-between;\n  gap: 12px;\n  align-items: center;\n  border: 1px solid var(--line);\n  background: var(--panel);\n  border-radius: 14px;\n  padding: 14px 15px;\n  transition: transform 180ms ease, box-shadow 180ms ease, border-color 180ms ease;\n}\n\n.list-row:hover,\n.priority-item:hover,\n.top-row:hover,\n.alert-card:hover {\n  transform: translateY(-2px);\n  border-color: rgba(214, 16, 16, 0.18);\n  box-shadow: 0 18px 30px rgba(15, 23, 42, 0.08);\n}\n\n.list-row p,\n.priority-item p,\n.top-row p,\n.alert-card p {\n  margin: 4px 0 0;\n  font-size: 0.84rem;\n}\n\n.right { text-align: right; }\n\n.top-row span {\n  width: 30px;\n  height: 30px;\n  border-radius: 50%;\n  display: grid;\n  place-items: center;\n  background: var(--accent);\n  color: #ffffff;\n  font-weight: 700;\n}\n\n.alert-card { background: color-mix(in srgb, var(--accent) 4%, var(--panel)); }\n.alert-card.ok { background: color-mix(in srgb, var(--ok) 8%, var(--panel)); }\n.empty-state { margin: 0; color: var(--muted); }\n\n@media (max-width: 1180px) {\n  .metrics-grid,\n  .dashboard-grid,\n  .content-grid {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n}\n\n@media (max-width: 880px) {\n  .app-shell { grid-template-columns: 1fr; }\n\n  .sidebar {\n    flex-direction: row;\n    justify-content: space-between;\n    align-items: flex-start;\n  }\n\n  .sidebar-nav {\n    grid-template-columns: repeat(6, minmax(0, 64px));\n    width: auto;\n  }\n\n  .topbar { grid-template-columns: 1fr; }\n  .topbar-right { justify-content: flex-start; }\n}\n\n@media (max-width: 640px) {\n  .page,\n  .topbar,\n  .sidebar {\n    padding: 16px;\n  }\n\n  .metrics-grid,\n  .dashboard-grid,\n  .content-grid,\n  .form-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .checkbox-row,\n  .form-grid button {\n    grid-column: span 1;\n  }\n\n  .list-row,\n  .priority-item,\n  .top-row,\n  .alert-card {\n    flex-direction: column;\n    align-items: flex-start;\n  }\n\n  .right { text-align: left; }\n}\n";
const js = "const currency = new Intl.NumberFormat('es-AR', {\n  style: 'currency',\n  currency: 'ARS',\n  maximumFractionDigits: 0,\n})\n\nconst today = new Date().toISOString().slice(0, 10)\nconst productName = 'Control'\nconst themeStorageKey = 'pclaf-control-theme'\n\nconst icon = (path) => `\n  <svg viewBox=\"0 0 24 24\" aria-hidden=\"true\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    ${path}\n  </svg>\n`\n\nconst seedData = {\n  business: {\n    name: 'Panel comercial',\n    branch: 'Floresta, CABA',\n  },\n  products: [\n    { id: crypto.randomUUID(), name: 'SSD Kingston 480GB', sku: 'SSD-480', stock: 12, price: 64000, minStock: 4, category: 'Hardware' },\n    { id: crypto.randomUUID(), name: 'Pasta termica MX-4', sku: 'PT-MX4', stock: 18, price: 12500, minStock: 6, category: 'Insumos' },\n    { id: crypto.randomUUID(), name: 'Fuente 500W generica', sku: 'FU-500', stock: 3, price: 47000, minStock: 5, category: 'Hardware' },\n    { id: crypto.randomUUID(), name: 'Limpieza completa notebook', sku: 'SERV-LIM', stock: 99, price: 38000, minStock: 0, category: 'Servicio' },\n  ],\n  providers: [\n    { id: crypto.randomUUID(), name: 'Mayorista Microglobal', contact: 'Daniel Perez', phone: '11 5011 4010', balance: 218000, lastDelivery: '2026-07-10', category: 'Hardware' },\n    { id: crypto.randomUUID(), name: 'Tecnoinsumos BA', contact: 'Marina Lopez', phone: '11 4321 9988', balance: 46000, lastDelivery: '2026-07-11', category: 'Insumos' },\n  ],\n  sales: [\n    { id: crypto.randomUUID(), item: 'Limpieza completa notebook', quantity: 1, amount: 38000, channel: 'Mostrador', paid: true, date: '2026-07-12' },\n    { id: crypto.randomUUID(), item: 'SSD Kingston 480GB', quantity: 2, amount: 128000, channel: 'WhatsApp', paid: true, date: '2026-07-12' },\n    { id: crypto.randomUUID(), item: 'Fuente 500W generica', quantity: 1, amount: 47000, channel: 'Mostrador', paid: false, date: '2026-07-11' },\n  ],\n  invoices: [\n    { id: crypto.randomUUID(), number: 'B-0001-001245', client: 'Juan Lopez', total: 38000, status: 'Cobrada', dueDate: '2026-07-12', type: 'B' },\n    { id: crypto.randomUUID(), number: 'A-0003-000184', client: 'Empresa Delta', total: 128000, status: 'Emitida', dueDate: '2026-07-20', type: 'A' },\n  ],\n}\n\nconst navItems = [\n  { id: 'dashboard', label: 'Inicio', icon: icon('<path d=\"M3 11.5 12 4l9 7.5\"/><path d=\"M5 10.5V20h14v-9.5\"/>') },\n  { id: 'ventas', label: 'Ventas', icon: icon('<path d=\"M4 17h16\"/><path d=\"M7 17V9\"/><path d=\"M12 17V5\"/><path d=\"M17 17v-6\"/>') },\n  { id: 'productos', label: 'Productos', icon: icon('<path d=\"M3 7.5 12 3l9 4.5-9 4.5-9-4.5Z\"/><path d=\"M3 7.5V16.5L12 21l9-4.5V7.5\"/>') },\n  { id: 'compras', label: 'Compras', icon: icon('<circle cx=\"9\" cy=\"19\" r=\"1.5\"/><circle cx=\"17\" cy=\"19\" r=\"1.5\"/><path d=\"M3 4h2l2.4 10.5h10.8L21 8H8\"/>') },\n  { id: 'facturacion', label: 'Facturas', icon: icon('<path d=\"M7 3h8l4 4v14H7z\"/><path d=\"M15 3v4h4\"/><path d=\"M10 12h6\"/><path d=\"M10 16h6\"/>') },\n  { id: 'reportes', label: 'Reportes', icon: icon('<path d=\"M5 19V9\"/><path d=\"M12 19V5\"/><path d=\"M19 19v-8\"/><path d=\"M3 19h18\"/>') },\n]\n\nconst storageKey = 'pclaf-control-data'\nconst app = document.querySelector('#app')\n\nconst loadState = () => {\n  const saved = localStorage.getItem(storageKey)\n  if (!saved) return structuredClone(seedData)\n\n  try {\n    return { ...structuredClone(seedData), ...JSON.parse(saved) }\n  } catch {\n    return structuredClone(seedData)\n  }\n}\n\nconst loadTheme = () => localStorage.getItem(themeStorageKey) || 'light'\n\nlet state = loadState()\nlet theme = loadTheme()\n\nconst saveState = () => {\n  localStorage.setItem(storageKey, JSON.stringify(state))\n}\n\nconst saveTheme = () => {\n  localStorage.setItem(themeStorageKey, theme)\n}\n\nconst applyTheme = () => {\n  document.documentElement.dataset.theme = theme\n}\n\nconst money = (value) => currency.format(Number(value) || 0)\n\nconst getMetrics = () => {\n  const totalSales = state.sales.reduce((sum, sale) => sum + sale.amount, 0)\n  const unpaidSales = state.sales.filter((sale) => !sale.paid).reduce((sum, sale) => sum + sale.amount, 0)\n  const payables = state.providers.reduce((sum, provider) => sum + provider.balance, 0)\n  const pendingInvoices = state.invoices.filter((invoice) => invoice.status !== 'Cobrada').reduce((sum, invoice) => sum + invoice.total, 0)\n  const lowStock = state.products.filter((product) => product.stock <= product.minStock)\n\n  return { totalSales, unpaidSales, payables, pendingInvoices, lowStock }\n}\n\nconst getTopProducts = () => {\n  const sold = new Map()\n\n  for (const sale of state.sales) {\n    sold.set(sale.item, (sold.get(sale.item) || 0) + sale.quantity)\n  }\n\n  return [...sold.entries()].sort((a, b) => b[1] - a[1]).slice(0, 5)\n}\n\nconst render = () => {\n  const metrics = getMetrics()\n  const topProducts = getTopProducts()\n\n  app.innerHTML = `\n    <div class=\"app-shell\">\n      <aside class=\"sidebar\">\n        <div class=\"sidebar-brand\">\n          <img class=\"brand-logo\" src=\"/pclaf-logo.png\" alt=\"PCLAF\" />\n        </div>\n\n        <nav class=\"sidebar-nav\">\n          ${navItems\n            .map(\n              (item) => `\n                <button class=\"nav-square\" type=\"button\" data-jump=\"${item.id}\" title=\"${item.label}\" aria-label=\"${item.label}\">\n                  <span class=\"nav-icon\">${item.icon}</span>\n                  <span class=\"nav-label\">${item.label}</span>\n                </button>`,\n            )\n            .join('')}\n        </nav>\n      </aside>\n\n      <div class=\"workspace\">\n        <header class=\"topbar\">\n          <div class=\"topbar-left\">\n            <p class=\"kicker\">Panel de control</p>\n            <h1>${productName}</h1>\n            <span>${state.business.branch}</span>\n          </div>\n          <div class=\"topbar-center\">\n            <div class=\"searchbar\">\n              <span>Buscar</span>\n              <input type=\"text\" placeholder=\"Productos, clientes, proveedores\" />\n            </div>\n          </div>\n          <div class=\"topbar-right\">\n            <button class=\"theme-toggle\" type=\"button\" data-action=\"toggle-theme\" aria-label=\"Cambiar tema\">\n              ${theme === 'dark' ? 'Modo claro' : 'Modo oscuro'}\n            </button>\n            <span class=\"badge\">Online</span>\n          </div>\n        </header>\n\n        <main class=\"page\">\n          <section class=\"metrics-grid\" id=\"dashboard\">\n            <article class=\"metric-card\">\n              <span>Ventas registradas</span>\n              <strong>${money(metrics.totalSales)}</strong>\n              <p>${state.sales.length} operaciones</p>\n            </article>\n            <article class=\"metric-card\">\n              <span>Por cobrar</span>\n              <strong>${money(metrics.unpaidSales)}</strong>\n              <p>${state.sales.filter((sale) => !sale.paid).length} pendientes</p>\n            </article>\n            <article class=\"metric-card\">\n              <span>Facturas abiertas</span>\n              <strong>${money(metrics.pendingInvoices)}</strong>\n              <p>${state.invoices.filter((invoice) => invoice.status !== 'Cobrada').length} comprobantes</p>\n            </article>\n            <article class=\"metric-card\">\n              <span>A pagar</span>\n              <strong>${money(metrics.payables)}</strong>\n              <p>${state.providers.length} proveedores activos</p>\n            </article>\n          </section>\n\n          <section class=\"dashboard-grid\">\n            <article class=\"panel\">\n              <div class=\"panel-head\">\n                <div>\n                  <h3>Ventas recientes</h3>\n                  <p>Lo ultimo que paso en caja</p>\n                </div>\n              </div>\n              <div class=\"list\">\n                ${state.sales\n                  .slice()\n                  .reverse()\n                  .slice(0, 6)\n                  .map(\n                    (sale) => `\n                      <div class=\"list-row\">\n                        <div>\n                          <strong>${sale.item}</strong>\n                          <p>${sale.date} - ${sale.channel}</p>\n                        </div>\n                        <div class=\"right\">\n                          <strong>${money(sale.amount)}</strong>\n                          <p>${sale.quantity} un. - ${sale.paid ? 'Cobrado' : 'Pendiente'}</p>\n                        </div>\n                      </div>`,\n                  )\n                  .join('')}\n              </div>\n            </article>\n\n            <article class=\"panel\">\n              <div class=\"panel-head\">\n                <div>\n                  <h3>Articulos mas vendidos</h3>\n                  <p>Ranking de movimiento</p>\n                </div>\n              </div>\n              <div class=\"top-list\">\n                ${topProducts.length\n                  ? topProducts\n                      .map(\n                        ([item, quantity], index) => `\n                          <div class=\"top-row\">\n                            <span>${index + 1}</span>\n                            <div>\n                              <strong>${item}</strong>\n                              <p>${quantity} unidades vendidas</p>\n                            </div>\n                          </div>`,\n                      )\n                      .join('')\n                  : '<p class=\"empty-state\">Todavia no hay ventas cargadas.</p>'}\n              </div>\n            </article>\n\n            <article class=\"panel\">\n              <div class=\"panel-head\">\n                <div>\n                  <h3>Alertas de stock</h3>\n                  <p>Productos para reponer</p>\n                </div>\n              </div>\n              <div class=\"alert-list\">\n                ${\n                  metrics.lowStock.length\n                    ? metrics.lowStock\n                        .map(\n                          (product) => `\n                            <div class=\"alert-card\">\n                              <strong>${product.name}</strong>\n                              <p>Stock ${product.stock} / minimo ${product.minStock}</p>\n                            </div>`,\n                        )\n                        .join('')\n                    : '<div class=\"alert-card ok\"><strong>Sin alertas criticas</strong><p>El inventario esta estable.</p></div>'\n                }\n              </div>\n            </article>\n\n            <article class=\"panel\">\n              <div class=\"panel-head\">\n                <div>\n                  <h3>Estado financiero</h3>\n                  <p>Cobros y compromisos</p>\n                </div>\n              </div>\n              <div class=\"priority-list\">\n                <div class=\"priority-item\">\n                  <strong>Cuentas por cobrar</strong>\n                  <p>${money(metrics.unpaidSales)} en operaciones pendientes</p>\n                </div>\n                <div class=\"priority-item\">\n                  <strong>Cuentas por pagar</strong>\n                  <p>${money(metrics.payables)} comprometidos con proveedores</p>\n                </div>\n                <div class=\"priority-item\">\n                  <strong>Facturas emitidas</strong>\n                  <p>${money(metrics.pendingInvoices)} aun no cerradas</p>\n                </div>\n              </div>\n            </article>\n          </section>\n\n          <section class=\"content-grid\">\n            <article class=\"panel\" id=\"ventas\">\n              <div class=\"panel-head\">\n                <div>\n                  <h3>Registrar venta</h3>\n                  <p>Carga rapida de operaciones</p>\n                </div>\n              </div>\n              <form class=\"form-grid\" data-form=\"sale\">\n                <label>\n                  Producto\n                  <select name=\"item\" required>\n                    ${state.products.map((product) => `<option value=\"${product.name}\">${product.name}</option>`).join('')}\n                  </select>\n                </label>\n                <label>\n                  Cantidad\n                  <input type=\"number\" name=\"quantity\" min=\"1\" value=\"1\" required />\n                </label>\n                <label>\n                  Monto total\n                  <input type=\"number\" name=\"amount\" min=\"1\" placeholder=\"38000\" required />\n                </label>\n                <label>\n                  Canal\n                  <select name=\"channel\">\n                    <option>Mostrador</option>\n                    <option>WhatsApp</option>\n                    <option>Transferencia</option>\n                    <option>Mercado Pago</option>\n                  </select>\n                </label>\n                <label class=\"checkbox-row\">\n                  <input type=\"checkbox\" name=\"paid\" checked />\n                  Cobrado\n                </label>\n                <button type=\"submit\">Registrar venta</button>\n              </form>\n            </article>\n\n            <article class=\"panel\" id=\"productos\">\n              <div class=\"panel-head\">\n                <div>\n                  <h3>Alta de productos</h3>\n                  <p>Stock, precios y categorias</p>\n                </div>\n              </div>\n              <form class=\"form-grid\" data-form=\"product\">\n                <label>\n                  Nombre\n                  <input type=\"text\" name=\"name\" placeholder=\"Mouse gamer USB\" required />\n                </label>\n                <label>\n                  SKU\n                  <input type=\"text\" name=\"sku\" placeholder=\"MO-USB\" required />\n                </label>\n                <label>\n                  Stock\n                  <input type=\"number\" name=\"stock\" min=\"0\" required />\n                </label>\n                <label>\n                  Precio\n                  <input type=\"number\" name=\"price\" min=\"0\" required />\n                </label>\n                <label>\n                  Minimo\n                  <input type=\"number\" name=\"minStock\" min=\"0\" required />\n                </label>\n                <label>\n                  Categoria\n                  <input type=\"text\" name=\"category\" placeholder=\"Perifericos\" required />\n                </label>\n                <button type=\"submit\">Guardar producto</button>\n              </form>\n            </article>\n\n            <article class=\"panel\" id=\"compras\">\n              <div class=\"panel-head\">\n                <div>\n                  <h3>Proveedores</h3>\n                  <p>Ingresos y saldos pendientes</p>\n                </div>\n              </div>\n              <form class=\"form-grid\" data-form=\"provider\">\n                <label>\n                  Empresa\n                  <input type=\"text\" name=\"name\" required />\n                </label>\n                <label>\n                  Contacto\n                  <input type=\"text\" name=\"contact\" required />\n                </label>\n                <label>\n                  Telefono\n                  <input type=\"text\" name=\"phone\" required />\n                </label>\n                <label>\n                  Saldo pendiente\n                  <input type=\"number\" name=\"balance\" min=\"0\" required />\n                </label>\n                <label>\n                  Ultima entrega\n                  <input type=\"date\" name=\"lastDelivery\" value=\"${today}\" required />\n                </label>\n                <label>\n                  Categoria\n                  <input type=\"text\" name=\"category\" required />\n                </label>\n                <button type=\"submit\">Guardar proveedor</button>\n              </form>\n            </article>\n\n            <article class=\"panel\" id=\"facturacion\">\n              <div class=\"panel-head\">\n                <div>\n                  <h3>Facturacion</h3>\n                  <p>Comprobantes y seguimiento</p>\n                </div>\n              </div>\n              <form class=\"form-grid\" data-form=\"invoice\">\n                <label>\n                  Numero\n                  <input type=\"text\" name=\"number\" placeholder=\"B-0001-001555\" required />\n                </label>\n                <label>\n                  Cliente\n                  <input type=\"text\" name=\"client\" required />\n                </label>\n                <label>\n                  Total\n                  <input type=\"number\" name=\"total\" min=\"1\" required />\n                </label>\n                <label>\n                  Tipo\n                  <select name=\"type\">\n                    <option>A</option>\n                    <option>B</option>\n                    <option>C</option>\n                  </select>\n                </label>\n                <label>\n                  Vencimiento\n                  <input type=\"date\" name=\"dueDate\" value=\"${today}\" required />\n                </label>\n                <label>\n                  Estado\n                  <select name=\"status\">\n                    <option>Emitida</option>\n                    <option>En revision</option>\n                    <option>Cobrada</option>\n                  </select>\n                </label>\n                <button type=\"submit\">Guardar factura</button>\n              </form>\n            </article>\n          </section>\n        </main>\n      </div>\n    </div>\n  `\n\n  bindEvents()\n}\n\nconst bindEvents = () => {\n  for (const form of document.querySelectorAll('form[data-form]')) {\n    form.addEventListener('submit', handleSubmit)\n  }\n\n  for (const button of document.querySelectorAll('[data-jump]')) {\n    button.addEventListener('click', () => {\n      const target = document.getElementById(button.dataset.jump)\n      if (target) target.scrollIntoView({ behavior: 'smooth', block: 'start' })\n    })\n  }\n\n  const toggle = document.querySelector('[data-action=\"toggle-theme\"]')\n  if (toggle) {\n    toggle.addEventListener('click', () => {\n      theme = theme === 'dark' ? 'light' : 'dark'\n      saveTheme()\n      applyTheme()\n      render()\n    })\n  }\n}\n\nconst handleSubmit = (event) => {\n  event.preventDefault()\n\n  const form = event.currentTarget\n  const formData = new FormData(form)\n  const kind = form.dataset.form\n\n  if (kind === 'sale') {\n    const item = formData.get('item')\n    const quantity = Number(formData.get('quantity'))\n    const amount = Number(formData.get('amount'))\n    const paid = formData.get('paid') === 'on'\n    const product = state.products.find((entry) => entry.name === item)\n\n    if (product) product.stock = Math.max(0, product.stock - quantity)\n\n    state.sales.push({\n      id: crypto.randomUUID(),\n      item,\n      quantity,\n      amount,\n      channel: formData.get('channel'),\n      paid,\n      date: today,\n    })\n  }\n\n  if (kind === 'product') {\n    state.products.push({\n      id: crypto.randomUUID(),\n      name: formData.get('name'),\n      sku: formData.get('sku'),\n      stock: Number(formData.get('stock')),\n      price: Number(formData.get('price')),\n      minStock: Number(formData.get('minStock')),\n      category: formData.get('category'),\n    })\n  }\n\n  if (kind === 'provider') {\n    state.providers.unshift({\n      id: crypto.randomUUID(),\n      name: formData.get('name'),\n      contact: formData.get('contact'),\n      phone: formData.get('phone'),\n      balance: Number(formData.get('balance')),\n      lastDelivery: formData.get('lastDelivery'),\n      category: formData.get('category'),\n    })\n  }\n\n  if (kind === 'invoice') {\n    state.invoices.push({\n      id: crypto.randomUUID(),\n      number: formData.get('number'),\n      client: formData.get('client'),\n      total: Number(formData.get('total')),\n      type: formData.get('type'),\n      dueDate: formData.get('dueDate'),\n      status: formData.get('status'),\n    })\n  }\n\n  saveState()\n  form.reset()\n  render()\n}\n\napplyTheme()\nrender()\n";
